import{_ as o,o as l,c as t,ag as a}from"./chunks/framework.CO09BnhD.js";const h=JSON.parse('{"title":"Everything Claude Code 深度学习指南","description":"","frontmatter":{},"headers":[],"relativePath":"常用skills/everything-claudecode.md","filePath":"常用skills/everything-claudecode.md","lastUpdated":1773312120000}'),i={name:"常用skills/everything-claudecode.md"};function d(r,e,n,c,s,g){return l(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="everything-claude-code-深度学习指南" tabindex="-1">Everything Claude Code 深度学习指南 <a class="header-anchor" href="#everything-claude-code-深度学习指南" aria-label="Permalink to &quot;Everything Claude Code 深度学习指南&quot;">​</a></h1><h2 id="_1-快速入门" tabindex="-1">1. 快速入门 <a class="header-anchor" href="#_1-快速入门" aria-label="Permalink to &quot;1. 快速入门&quot;">​</a></h2><p><strong>Everything Claude Code</strong> 是 Anthropic 黑客马拉松获胜项目，包含 15+ 代理、30+ 技能、20+ 命令及自动化钩子。</p><ul><li><strong>安装</strong>: <ol><li>添加市场: <code>/plugin marketplace add affaan-m/everything-claude-code</code></li><li>安装插件: <code>/plugin install everything-claude-code@everything-claude-code</code></li><li>配置规则: <code>cp -r everything-claude-code/rules/* ~/.claude/rules/</code></li></ol></li></ul><h2 id="_2-核心概念" tabindex="-1">2. 核心概念 <a class="header-anchor" href="#_2-核心概念" aria-label="Permalink to &quot;2. 核心概念&quot;">​</a></h2><ul><li><strong>Skills (技能)</strong>: 工作流定义与领域知识封装 (位于 <code>~/.claude/skills/</code>)。提供 Codemaps 辅助导航，减少重复提示。</li><li><strong>Commands (命令)</strong>: 存储在 <code>~/.claude/commands/</code> 的快速执行提示词，如 <code>/plan</code>, <code>/tdd</code>, <code>/code-review</code>, <code>/verify</code>。</li><li><strong>Agents (子代理)</strong>: 任务委托机制。例如 <code>planner</code> (规划)、<code>architect</code> (架构)、<code>tdd-guide</code> (测试)、<code>code-reviewer</code> (审查) 等。支持 Opus、Sonnet 或 Haiku 模型根据任务复杂度切换。</li><li><strong>Hooks (钩子)</strong>: 事件驱动自动化。支持 <code>PreToolUse</code> (工具前验证)、<code>Stop</code> (会话结束评估) 等 10+ 触发时机。</li><li><strong>Rules (规则)</strong>: 始终遵循的最佳实践，存储在 <code>~/.claude/rules/</code>。</li><li><strong>MCPs</strong>: 连接外部服务 (Supabase, GitHub, Chrome 等)。注意上下文窗口消耗。</li><li><strong>Plugins</strong>: 打包工具包。</li></ul><h2 id="_3-设计理念" tabindex="-1">3. 设计理念 <a class="header-anchor" href="#_3-设计理念" aria-label="Permalink to &quot;3. 设计理念&quot;">​</a></h2><ul><li><strong>Token 优化</strong>: 采用子代理架构，根据任务匹配模型 (如简单任务用 Haiku，复杂逻辑用 Opus)。</li><li><strong>内存持久化</strong>: 跨会话保存状态，使用会话存储文件 (<code>.tmp</code> 或 <code>sessions/</code>)。</li><li><strong>持续学习</strong>: 通过 <code>Stop Hook</code> 自动从会话中提取有效模式并存为新技能。</li><li><strong>验证循环</strong>: 强制质量检查 (Build -&gt; Types -&gt; Lint -&gt; Tests -&gt; Security -&gt; Diff)。</li></ul><h2 id="_4-核心工作流" tabindex="-1">4. 核心工作流 <a class="header-anchor" href="#_4-核心工作流" aria-label="Permalink to &quot;4. 核心工作流&quot;">​</a></h2><ul><li><strong>规划-实现-验证 (PIV) 循环</strong>: <code>/plan</code> 生成详细计划 -&gt; 用户确认 -&gt; <code>implementation</code> -&gt; <code>/verify</code> 自动报告。</li><li><strong>TDD 工作流</strong>: 测试优先原则，要求 80%+ 测试覆盖率。</li></ul><h2 id="_5-skill-详解" tabindex="-1">5. SKILL 详解 <a class="header-anchor" href="#_5-skill-详解" aria-label="Permalink to &quot;5. SKILL 详解&quot;">​</a></h2><ul><li><strong>TDD Workflow SKILL</strong>: 覆盖单元、集成和 E2E 测试模式。</li><li><strong>Continuous Learning SKILL</strong>: 评估会话长度 (默认 10+ 消息) 并自动提取知识。</li><li><strong>Verification Loop SKILL</strong>: 提供全面的验证报告 (PASS/FAIL 及错误计数)。</li></ul>',12)])])}const p=o(i,[["render",d]]);export{h as __pageData,p as default};
